class Solution(object):
    def bestCoordinate(self, towers, radius):
        max_quality = 0
        best_coord = [0, 0]
        min_x = min(t[0] for t in towers)
        max_x = max(t[0] for t in towers)
        min_y = min(t[1] for t in towers)
        max_y = max(t[1] for t in towers)
        for x in range(min_x, max_x + 1):
            for y in range(min_y, max_y + 1):
                quality = 0
                for tx, ty, q in towers:
                    dist = ((x - tx)**2 + (y - ty)**2)**0.5
                    if dist <= radius:
                        quality += q // (1 + dist)
                if quality > max_quality or (quality == max_quality and (x, y) < best_coord):
                    max_quality = quality
                    best_coord = [x, y]
        return best_coord
